f=normalizeargs(args:$str):$str{
    let keys=@();

    if(s.contains(args;"\"q\"")){
        keys=keys+@("q");
    };
    if(s.contains(args;"\"url\"")){
        keys=keys+@("url");
    };
    if(s.contains(args;"\"method\"")){
        keys=keys+@("method");
    };

    let sorted=mut.keys;

    lp(let idx=0;idx<sorted.len-1;idx=idx+1){
        lp(let jdx=idx+1;jdx<sorted.len;jdx=jdx+1){
            let a=sorted.get(idx);
            let b=sorted.get(jdx);
            if(a>b){
                sorted.set(idx;b);
                sorted.set(jdx;a);
            };
        };
    };

    let parts=mut.@();
    lp(let idx=0;idx<sorted.len;idx=idx+1){
        let key=sorted.get(idx);
        let searchkey=s.concat("\"";s.concat(key;"\":"));
        let startpos=s.indexof(args;searchkey);
        if(startpos>=0){
            let valstart=startpos+s.len(searchkey);
            let valend=mut.valstart;
            let inquote=mut.false;
            let depth=mut.0;

            lp(valend<s.len(args)){
                let ch=s.slice(args;valend;valend+1);
                if(ch="\""){
                    if(valend>0){
                        let prev=s.slice(args;valend-1;valend);
                        if(prev!="\\"){
                            inquote=!inquote;
                        };
                    }el{
                        inquote=!inquote;
                    };
                };
                if(!inquote){
                    if(ch="{"){
                        depth=depth+1;
                    };
                    if(ch="}"){
                        depth=depth-1;
                    };
                    if(depth=0){
                        let isc=ch=",";
                        let isb=ch="}";
                        if(isc||isb){
                            br;
                        };
                    };
                };
                valend=valend+1;
            };

            let val=s.slice(args;valstart;valend);
            let pair=s.concat(key;"::");
            pair=s.concat(pair;val);
            parts=parts+@(pair);
        };
    };

    <s.join(parts;"|")
};

